// ── availability-engine / slots ──────────────────────────────────────────────
// Input: POST body with customer_id, from, to, duration_minutes, timezone
// tenant_id comes from x-tenant-id header (injected by the API Gateway from JWT).
// Algorithm:
//   1. Load working hours (ae_get_working_hours)
//   2. Load busy periods (ae_get_busy_periods)
//   3. Load day exceptions (ae_get_day_exceptions)
//   4. For each day in range: expand working windows, subtract busy, slice into slots
//   5. Return { success: true, data: [{ start, end }, ...] }

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

function supabaseRpc(fnName, params) {
  return $helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/${fnName}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation',
    },
    body: JSON.stringify(params),
  });
}

// ── Slot calculation helpers ──────────────────────────────────────────────────

/** Convert 'HH:MM' on a date string to a UTC ms timestamp in the given timezone. */
function localTimeToMs(dateStr, timeStr, tz) {
  // Create a Date by interpreting dateStr + timeStr as a local time in tz.
  // We use Intl to find the UTC offset for that local moment.
  const isoLike = `${dateStr}T${timeStr}:00`;
  // Approximate: parse the dateStr+timeStr as if it were UTC, then adjust
  // using the tz offset at that moment. This is a best-effort approach.
  const naiveMs = new Date(isoLike + 'Z').getTime();
  // Compute the offset in that timezone at that moment.
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: false,
  });
  // Parse the local representation back to get offset.
  const parts = fmt.formatToParts(new Date(naiveMs));
  const p = {};
  for (const { type, value } of parts) p[type] = value;
  const localMs = Date.UTC(
    parseInt(p.year), parseInt(p.month) - 1, parseInt(p.day),
    parseInt(p.hour === '24' ? '0' : p.hour), parseInt(p.minute), parseInt(p.second)
  );
  const offsetMs = localMs - naiveMs;
  // Actual UTC ms = naive UTC ms - offset
  return naiveMs - offsetMs;
}

/** Returns the day-of-week (0=Sun…6=Sat) for a UTC date at given timezone. */
function getDow(tsMs, tz) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz, weekday: 'short',
  }).formatToParts(new Date(tsMs));
  const day = parts.find(p => p.type === 'weekday').value;
  return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].indexOf(day);
}

/** Returns YYYY-MM-DD for a UTC ms timestamp in the given timezone. */
function toDateStr(tsMs, tz) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit',
  });
  return fmt.format(new Date(tsMs)); // en-CA gives YYYY-MM-DD
}

/** Checks whether [slotStart, slotEnd) overlaps any busy window in the sorted array. */
function overlapsAny(slotStartMs, slotEndMs, busyWindows) {
  for (const b of busyWindows) {
    if (slotStartMs < b.endMs && slotEndMs > b.startMs) return true;
  }
  return false;
}

// ── Main ──────────────────────────────────────────────────────────────────────

const item       = $input.first();
const headers    = item.json.headers || {};
const body       = item.json.body   || {};
const tenantId   = headers['x-tenant-id'];

const { customer_id, from, to, timezone = 'Europe/Berlin' } = body;
const durationMin = Number(body.duration_minutes) || 30;
const durationMs  = durationMin * 60 * 1000;
const fromMs      = new Date(from).getTime();
const toMs        = new Date(to).getTime();

// Fetch data from DB
let workingHours, busyPeriods, exceptions;
try {
  [workingHours, busyPeriods, exceptions] = await Promise.all([
    supabaseRpc('ae_get_working_hours', {
      p_tenant_id: tenantId, p_customer_id: customer_id,
    }),
    supabaseRpc('ae_get_busy_periods', {
      p_tenant_id: tenantId, p_customer_id: customer_id, p_from: from, p_to: to,
    }),
    supabaseRpc('ae_get_day_exceptions', {
      p_tenant_id: tenantId, p_customer_id: customer_id,
      p_from_date: toDateStr(fromMs, timezone),
      p_to_date:   toDateStr(toMs,   timezone),
    }),
  ]);
} catch (err) {
  return [{ json: { success: false, error: { code: 'DB_ERROR', message: err.message } } }];
}

// Build lookup maps
const whByDow = {};
for (const wh of (workingHours || [])) {
  const d = wh.day_of_week;
  if (!whByDow[d]) whByDow[d] = [];
  whByDow[d].push(wh);
}

const busyWindows = (busyPeriods || []).map(b => ({
  startMs: new Date(b.start_at).getTime(),
  endMs:   new Date(b.end_at).getTime(),
}));

const closedDates = new Set();
const partialBlocks = []; // { dateStr, startMs, endMs }
for (const ex of (exceptions || [])) {
  if (ex.is_closed) {
    closedDates.add(ex.date);
  } else if (ex.start_time_txt && ex.end_time_txt) {
    partialBlocks.push({
      dateStr: ex.date,
      startMs: localTimeToMs(ex.date, ex.start_time_txt, timezone),
      endMs:   localTimeToMs(ex.date, ex.end_time_txt,   timezone),
    });
  }
}

// Generate free slots day by day
const slots = [];
let cursor = fromMs;
const DAY_MS = 86400000;

while (cursor < toMs) {
  const dateStr = toDateStr(cursor, timezone);
  const dow     = getDow(cursor, timezone);

  if (!closedDates.has(dateStr) && whByDow[dow]) {
    const dayPartialBusy = partialBlocks
      .filter(pb => pb.dateStr === dateStr)
      .concat(busyWindows);

    for (const wh of whByDow[dow]) {
      const bufBefore = (wh.buffer_before_min || 0) * 60000;
      const bufAfter  = (wh.buffer_after_min  || 0) * 60000;

      let winStart = Math.max(localTimeToMs(dateStr, wh.start_time_text, timezone), fromMs);
      let winEnd   = Math.min(localTimeToMs(dateStr, wh.end_time_text,   timezone), toMs);

      if (winStart >= winEnd) continue;

      // Expand busy windows with buffers
      const buffered = dayPartialBusy.map(b => ({
        startMs: b.startMs - bufBefore,
        endMs:   b.endMs   + bufAfter,
      }));

      let t = winStart;
      while (t + durationMs <= winEnd) {
        if (!overlapsAny(t, t + durationMs, buffered)) {
          slots.push({
            start: new Date(t).toISOString(),
            end:   new Date(t + durationMs).toISOString(),
          });
        }
        t += durationMs;
      }
    }
  }

  // Advance to next day in the timezone
  const nextDateStr = toDateStr(cursor + DAY_MS, timezone);
  if (nextDateStr === dateStr) {
    cursor += DAY_MS; // DST edge: force advance
  } else {
    cursor += DAY_MS;
  }
}

return [{ json: { success: true, data: slots } }];
